#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    // Calculate coefficients
    float v_41 = step / Cap;
    float var_23 = 1.0f / Rx;
    float elem_44 = 1.0f / Ry;
    float var_32 = 1.0f / Rz;

    int block_id_x = get_group_id(0);
    int block_id_y = get_group_id(1);

    int start_x = block_id_x * BLOCK_SIZE;
    int start_y = block_id_y * BLOCK_SIZE;

    int end_x = start_x + BLOCK_SIZE;
    int end_y = start_y + BLOCK_SIZE;

    // Clamp to grid size
    if (start_x >= col || start_y >= row) return;
    if (end_x > col) end_x = col;
    if (end_y > row) end_y = row;

    // Process iterations
    // The interface allows only 1 effective step per call due to const temp and single result buffer.
    // The host code is expected to handle multiple steps by swapping buffers and calling the kernel repeatedly,
    // or by passing num_iterations=1.
    for (int iter = 0; iter < num_iterations; iter++) {
        for (int r = start_y; r < end_y; r++) {
            for (int c = start_x; c < end_x; c++) {
                int idx = r * col + c;
                float delta;

                bool is_left = (c == 0);
                bool is_right = (c == col - 1);
                bool is_top = (r == 0);
                bool is_bottom = (r == row - 1);

                if (is_top && is_left) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * var_23 +
                        (temp[idx + col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_top && is_right) {
                    delta = v_41 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * var_23 +
                        (temp[idx + col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_bottom && is_right) {
                    delta = v_41 * (power[idx] +
                        (temp[idx - 1] - temp[idx]) * var_23 +
                        (temp[idx - col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_bottom && is_left) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] - temp[idx]) * var_23 +
                        (temp[idx - col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_top) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                        (temp[idx + col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_right) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx - 1] - temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_bottom) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                        (temp[idx - col] - temp[idx]) * elem_44 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else if (is_left) {
                    delta = v_41 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx + 1] - temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }
                else {
                    delta = v_41 * (power[idx] +
                        (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * elem_44 +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * var_23 +
                        (amb_temp - temp[idx]) * var_32);
                }

                result[idx] = temp[idx] + delta;
            }
        }
        // Cannot proceed to next iteration without swapping buffers, which is not possible here.
        // Break to avoid incorrect computation if num_iterations > 1.
        if (num_iterations > 1) break;
    }
}
